import{_ as t,o as r,c as a,a3 as i}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"74A. Foster And Kinship Care","description":"","frontmatter":{"title":"74A. Foster And Kinship Care","eba":"Nurses and Midwives 2024-2028","topics":["leave","preliminary"]},"headers":[],"relativePath":"ebas/nurses-midwives/leave/74A-foster-and-kinship-care.md","filePath":"ebas/nurses-midwives/leave/74A-foster-and-kinship-care.md"}'),o={name:"ebas/nurses-midwives/leave/74A-foster-and-kinship-care.md"};function n(s,e,p,l,h,d){return r(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="_74a-foster-and-kinship-care" tabindex="-1">74A. Foster And Kinship Care <a class="header-anchor" href="#_74a-foster-and-kinship-care" aria-label="Permalink to &quot;74A. Foster And Kinship Care&quot;">​</a></h1><p><strong>74A.1</strong> From 24 June 2024, an Employee who provides short-term foster or kinship care as the primary caregiver to a child who cannot live with their parents as a result of an eligible child protection intervention is entitled to up to two days&#39; paid leave on up to five occasions per calendar year to be taken at the time the placement of the child with the Employee commences.</p><p><strong>74A.2</strong> For the purposes of this clause Foster and Kinship Care includes:</p><p><strong>(a)</strong> Foster Caring, which is the temporary care of a child of up to 18 years of age on a short-term basis by an Employee who is an accredited foster carer;</p><p><strong>(b)</strong> Kinship Care, which is temporary care provided by an Employee who is a relative or a member of the child&#39;s social network when the child cannot live with their parents; and/or</p><p><strong>(c)</strong> Aboriginal Kinship Care, which is temporary care provided by an Employee who is a relative or friend of an Aboriginal child who cannot live with their parents, where Aboriginal family and community and Aboriginal culture are valued as central to the child’s safety, stability and development.</p><p><strong>74A.3</strong> Eligible child protection interventions include emergency respite and short-term or long- term placements on a non-permanent basis, as issued by the Victorian Department of Health, the Children’s Court or other similar federal, state or judicial authority.</p><p><strong>74A.4</strong> Subject to the approval of the Employer, the paid leave provided in this clause may be used in conjunction with any other paid or unpaid leave entitlements the Employee may be eligible for under this Agreement.</p><p><strong>74A.5</strong> In the case of foster carers, one occasion totalling up to two days duration may be used for accreditation purposes, including attending compulsory interviews or training.</p><p><strong>74A.6</strong> The Employer may require the Employee to provide reasonable evidence to satisfy themselves of the Employee’s entitlement to leave under this provision .</p><p>Plain language terms: foster leave, kinship leave, carer leave.</p>',11)])])}const u=t(o,[["render",n]]);export{m as __pageData,u as default};
